INSERT INTO guided_scenarios (id, slug, title_ar, title_fr, description_ar, description_fr, icon_emoji, target_level, objectives, steps, display_order, is_active, created_at) VALUES (1, 'se-presentee', 'التعريف بالنفس', 'Se présenter', 'عرّف بنفسك بالعربية — اسمك، عمرك، مدينتك، عملك', 'Présentez-vous en arabe : nom, âge, ville, métier', '👋', 'debutant', 'Dire son nom, son âge, sa ville, son métier', '[{"hint_ar":"قل: \\"السلام عليكم، اسمي محمد\\"","objective":"Saluer poliment","prompt_ar":"أهلاً! أنا أبو آدم، معلّم اللغة العربية. سنتدرّب على التعريف بالنفس. ابدأ بالسلام بالعربية!","step_description":"Saluer"},{"hint_ar":"قل: \\"اسمي [اسمك]\\"","objective":"Dire son nom","prompt_ar":"أحسنت! الآن أخبرني: ما اسمك؟","step_description":"Dire son nom"},{"hint_ar":"قل: \\"عمري [عدد] سنة\\"","objective":"Dire son âge","prompt_ar":"جميل! كم عمرك؟","step_description":"Dire son âge"},{"hint_ar":"قل: \\"أنا من الجزائر\\" أو \\"أنا من المغرب\\"","objective":"Dire sa ville","prompt_ar":"ممتاز! من أين أنت؟","step_description":"Dire doù on vient"},{"hint_ar":"قل: \\"أنا طالب\\" أو \\"أنا معلّم\\" أو \\"أنا طبيب\\"","objective":"Dire son métier","prompt_ar":"أحسنت! هل تعمل أو تدرس؟","step_description":"Parler de son métier"},{"hint_ar":"قل: \\"شكراً، مع السلامة!\\"","objective":"Terminer poliment","prompt_ar":"تشرفت بمعرفتك! مع السلامة!","step_description":"Terminer"}]', 1, 'true', '2026-05-28T16:51:20.241Z');
INSERT INTO guided_scenarios (id, slug, title_ar, title_fr, description_ar, description_fr, icon_emoji, target_level, objectives, steps, display_order, is_active, created_at) VALUES (2, 'au-marche', 'في السوق', 'Au marché', 'اشترِ الفواكه والخضروات من البائع في السوق', 'Achetez des fruits et légumes au marché en arabe', '🍎', 'debutant', 'Saluer, demander le prix, acheter, payer, dire au revoir', '[{"hint_ar":"جرب: مرحباً، كيف حالك؟","objective":"Saluer le vendeur avec politesse","prompt_ar":"بائع: مرحباً! ماذا تريد اليوم؟","step_description":"Saluer le vendeur"},{"hint_ar":"أريد تفاح أو برتقال","objective":"Dire ce quon veut acheter","prompt_ar":"بائع: ماذا تريد أن تشتري؟","step_description":"Demander des fruits"},{"hint_ar":"كم السعر؟","objective":"Poser une question sur le prix","prompt_ar":"بائع: عندي تفاح طازج وبطاطس!","step_description":"Demander le prix"},{"hint_ar":"سآخذ كيلو واحد","objective":"Répondre à une offre de prix","prompt_ar":"بائع: الكيلو بخمسة دراهم فقط!","step_description":"Acheter"},{"hint_ar":"شكراً، مع السلامة!","objective":"Payer et dire au revoir","prompt_ar":"بائع: هذا كيلو التفاح. شكراً لك!","step_description":"Payer et saluer"}]', 2, 'true', '2026-05-28T16:51:20.241Z');
INSERT INTO guided_scenarios (id, slug, title_ar, title_fr, description_ar, description_fr, icon_emoji, target_level, objectives, steps, display_order, is_active, created_at) VALUES (3, 'a-la-mosquee', 'في المسجد', 'À la mosquée', 'تعلّم ما يقوله المسلم في المسجد — الاستئذان، الوضوء، سؤال الإمام', 'Communiquez à la mosquée : demander la permission, faire ablution, poser une question à l''imam', '🕌', 'intermediaire', 'Demander où faire ablution, dire quelle prière on veut, demander l''horaire', '[{"hint_ar":"قل: \\"عليكم السلام، بخير الحمد لله\\"","objective":"Saluer correctement","prompt_ar":"رجل: السلام عليكم! كيف حالك؟","step_description":"Saluer"},{"hint_ar":"أين مكان الوضوء من فضلك؟","objective":"Demander le lieu d''ablution","prompt_ar":"رجل: أهلاً! تريد شيء؟","step_description":"Demander où est le marbre"},{"hint_ar":"نعم، أريد أن أصلي الظهر","objective":"Exprimer quelle prière on veut","prompt_ar":"رجل: مكان الوضوء هناك. تريد أن تصلي مع الجماعة؟","step_description":"Dire quelle prière"},{"hint_ar":"متى صلاة المغرب؟","objective":"Demander l''horaire de prière","prompt_ar":"رجل: الظهر بعد ساعة. هل عندك سؤال آخر؟","step_description":"Demander l''horaire"},{"hint_ar":"جزاك الله خيراً، مع السلامة!","objective":"Se séparer poliment","prompt_ar":"رجل: جزاك الله خيراً! نراك بعد الصلاة.","step_description":"Se séparer"}]', 3, 'true', '2026-05-28T16:51:20.241Z');
INSERT INTO guided_scenarios (id, slug, title_ar, title_fr, description_ar, description_fr, icon_emoji, target_level, objectives, steps, display_order, is_active, created_at) VALUES (4, 'chez-le-medecin', 'عند الطبيب', 'Chez le médecin', 'اشرح أعراضك للطبيب وتلقَّ نصيحة', 'Expliquez vos symptômes à un médecin', '🏥', 'intermediaire', 'Décrire des symptômes, répondre aux questions du médecin, comprendre les conseils', '[{"hint_ar":"لدي ألم في رأسي منذ يومين","objective":"Se plaindre d''un symptôme","prompt_ar":"طبيب: مرحباً! كيف حالك؟ لماذا أتيت اليوم؟","step_description":"Saluer et expliquer pourquoi"},{"hint_ar":"منذ يومين، ولا أحس بحمى","objective":"Donner des détails sur la maladie","prompt_ar":"طبيب: منذ متى؟ هل عندك حمى؟","step_description":"Donner plus de détails"},{"hint_ar":"نعم، آكل ثلاث مرات وأشرب ماء كثيراً","objective":"Répondre aux questions du médecin","prompt_ar":"طبيب: هل تأكل جيداً؟ هل تشرب الماء كثيراً؟","step_description":"Répondre aux questions"},{"hint_ar":"متى آخذ الدواء؟","objective":"Demander les instructions","prompt_ar":"طبيب: خذ هذا الدواء ثلاث مرات في اليوم","step_description":"Demander le traitement"},{"hint_ar":"شكراً جزيلاً، مع السلامة!","objective":"Remercier et saluer","prompt_ar":"طبيب: اشرب ماء كثيراً وارتح. مع السلامة!","step_description":"Remercier"}]', 4, 'true', '2026-05-28T16:51:20.241Z');
INSERT INTO guided_scenarios (id, slug, title_ar, title_fr, description_ar, description_fr, icon_emoji, target_level, objectives, steps, display_order, is_active, created_at) VALUES (5, 'a-lecole', 'في المدرسة', 'À l''école', 'تحدّث عن يومك في المدرسة مع صديقك.', 'Parlez de votre journée à l''école avec un ami', '📚', 'debutant', 'Saluer, parler des matières, demander à un ami', '[{"hint_ar":"أهلاً! كان جيداً. كيف كان يومك؟","objective":"Saluer et commencer une conversation","prompt_ar":"صديق: أهلاً! كيف كان يومك في المدرسة؟","step_description":"Saluer un camarade"},{"hint_ar":"درست العربية والعلوم","objective":"Parler des matières qu''on étudie","prompt_ar":"صديق: أنا درست العربية والرياضيات. ما المواد التي درستها أنت؟","step_description":"Parler des matieres"},{"hint_ar":"نعم، أحب الرياضيات كثيراً","objective":"Exprimer une opinion","prompt_ar":"صديق: جميل! هل تحب مادة الرياضيات؟","step_description":"Parler de l''ami"},{"hint_ar":"إلى اللقاء! مع السلامة!","objective":"Se dire au revoir poliment","prompt_ar":"صديق: أراك غداً! إلى اللقاء!","step_description":"Se dire au revoir"}]', 5, 'true', '2026-05-28T16:51:20.241Z');
INSERT INTO guided_scenarios (id, slug, title_ar, title_fr, description_ar, description_fr, icon_emoji, target_level, objectives, steps, display_order, is_active, created_at) VALUES (6, 'le-voyage', 'السفر', 'Le voyage', 'تمرّن على محادثة في المطار والفندق — حجز رحلة، سؤال عن الفندق', 'Pratiquez les conversations à l''aéroport et à l''hôtel', '✈️', 'intermediaire', 'Donner son nom de réservation, demander le prix, demander les directions', '[{"hint_ar":"أهلاً! أنا عندي حجز، اسمي محمد","objective":"Donner le but de sa visite","prompt_ar":"موظف: مرحباً! كيف يمكنني مساعدتك؟","step_description":"Donner son nom"},{"hint_ar":"كم تكلف الغرفة في الليلة؟","objective":"Demander le prix de la chambre","prompt_ar":"موظف: نعم، وجدنا الحجز! كميلة الغرفة؟","step_description":"Demander le prix"},{"hint_ar":"نعم، أريدها. هل فيها إنترنت؟","objective":"Confirmer ou négocier","prompt_ar":"موظف: الغرفة 200 ريال مع الإفطار. تريدها؟","step_description":"Confirmer la réservation"},{"hint_ar":"نعم من فضلك. أين التاكسي؟","objective":"Demander les directions","prompt_ar":"موظف: نعم! الغرفة 305. تريد سيارة أجرة للفندق؟","step_description":"Demander les directions"},{"hint_ar":"شكراً جزيلاً! مع السلامة!","objective":"Remercier et se séparer","prompt_ar":"موظف: التاكسي هناك! شكراً لك ومساءلة!","step_description":"Remercier et se séparer"}]', 6, 'true', '2026-05-28T16:51:20.241Z');
