INSERT INTO oustaz_conversations (id, student_id, role, content, mode, created_at) VALUES (93, 5, 'user', 'سلام', 'libre', '2026-05-11T09:09:27.411Z');
INSERT INTO oustaz_conversations (id, student_id, role, content, mode, created_at) VALUES (94, 5, 'assistant', 'وعليكم السلام ورحمة الله وبركاته يا سليمان.\n\nكيف حالك اليوم؟ وكيف حال الدراسة؟ \nأنا أستاذك أبو آدم، وأنا سعيد جداً بالتحدث معك باللغة العربية.\n\nهل أنت مستعد لنبدأ المحادثة في مستوانا الأول؟ وكيف يمكنني أن أساعدك اليوم؟', 'libre', '2026-05-11T09:09:27.465Z');
INSERT INTO oustaz_conversations (id, student_id, role, content, mode, created_at) VALUES (95, 5, 'user', 'سلام', 'libre', '2026-05-11T09:09:29.610Z');
INSERT INTO oustaz_conversations (id, student_id, role, content, mode, created_at) VALUES (96, 5, 'assistant', 'وعليكم السلام ورحمة الله وبركاته يا سليمان.\n\nأهلاً بك في مدرسة ميدين إيمرسيون. أنا أستاذك أبو آدم.\n\nكيف حالك اليوم؟ هل أنت مستعد لنتحدث قليلاً باللغة العربية؟', 'libre', '2026-05-11T09:09:29.665Z');
